+++ b/ACHNBrowserUI/ACHNBrowserUI/packages/Backend/Sources/Backend/extensions/Collection.swift
@@ -10,8 +10,8 @@ import Foundation


 public extension BidirectionalCollection where Element == Item {
-    func filterActive() -> [Item] {
